32	static std::string format_time(const std::chrono::system_clock::time_point & now, const std::string & format) {
33	    auto               time       = std::chrono::system_clock::to_time_t(now);
34	    auto               local_time = *std::localtime(&time);
35	    std::ostringstream ss;
36	    ss << std::put_time(&local_time, format.c_str());
37	    auto res = ss.str();
38	    return res;
39	}
