53	static std::string string_diff(const std::string & last, const std::string & current) {
54	    if (last.empty()) {
55	        return current;
56	    }
57	    if (!string_starts_with(current, last)) {
58	        if (string_starts_with(last, current)) {
59	            // This happens if the last generation ended on a partial stop word (not erased),
60	            // and the current ended on a stop word (erased).
61	            return "";
62	        }
63	        throw std::runtime_error("Invalid diff: '" + last + "' not found at start of '" + current + "'");
64	    }
65	    return current.substr(last.size());
66	}
